export class HrDashboardComponent implements OnInit, OnDestroy {
  // Logic Variables
  title = ''; location = ''; ctc = ''; description = ''; companyName = '';
  internships: any[] = []; applications: any[] = []; interviewerList: any[] = [];
  scheduleData: any = {}; selectedCandidate: any = null; offerFiles: any = {};
  uploadedOfferForApp: Record<string, string> = {}; pdfFile: any = null;
  uploadedFileName = ''; pdfUploaded = false; onboardingList: any[] = [];
  employeeList: any[] = []; 

  private intervalId: any;
  private pollingPaused = false;
  private refreshTimer: any;

  constructor(public auth: AuthService, private http: HttpClient, public router: Router) {}

  ngOnInit() {
    if (!this.auth.user || this.auth.user.role !== 'HR') {
      this.router.navigate(['/']);
      return;
    }
    this.fetchAll();
    this.startPolling();
  }

  ngOnDestroy() { this.stopPolling(); }

  startPolling() {
    this.stopPolling();
    this.intervalId = setInterval(() => { if (!this.pollingPaused) this.fetchAll(); }, 8000);
  }

  stopPolling() { if (this.intervalId) { clearInterval(this.intervalId); this.intervalId = null; } }
  pausePolling() { this.pollingPaused = true; }
  resumePolling() { this.pollingPaused = false; }
  logout() { this.auth.logout(); this.router.navigate(['/']); }

  private fetchAll() {
    Promise.all([
      this.fetchInternships(),
      this.fetchApplications(),
      this.fetchOnboarding(),
      this.fetchEmployees()
    ]);
  }

  // --- Core API Logic (Preserved exactly) ---
  async fetchOnboarding() { try { const res: any = await this.http.get('http://localhost:8080/api/onboarding').toPromise(); this.onboardingList = res || []; } catch (err) {} }
  async fetchInternships() { try { this.internships = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); } catch (err) {} }
  async fetchApplications() { try { this.applications = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise(); } catch (err) {} }
  async fetchEmployees() { try { this.employeeList = await this.http.get<any[]>('http://localhost:8080/api/employees').toPromise(); } catch (err) {} }

  formatDate(d: any) { return d ? new Date(d).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }) : ''; }
  formatTime(t: string) { if (!t) return ''; const [h, m] = t.split(':'); const d = new Date(); d.setHours(Number(h), Number(m)); return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }); }

  getInterviewerName(id: number) {
    const known: Record<number, string> = { 1: 'Kavya', 2: 'Arun', 3: 'Divya' };
    if (known[id]) return known[id];
    const emp = this.employeeList?.find(e => (e.id ?? e.interviewerId ?? e.employeeId) === id);
    return emp ? (emp.name ?? emp.fullName ?? emp.email) : '';
  }

  onPdfSelected(e: any) { this.pdfFile = e.target.files?.[0]; }

  async handlePdfUpload() {
    if (!this.pdfFile) return alert('Select PDF');
    const form = new FormData(); form.append('file', this.pdfFile);
    const res = await this.http.post('http://localhost:8080/api/internships/upload-pdf', form, { responseType: 'text' }).toPromise();
    this.uploadedFileName = res as string; this.pdfUploaded = true;
  }

  async handlePost() {
    const form = new FormData();
    form.append('companyName', this.companyName); form.append('title', this.title);
    form.append('location', this.location); form.append('ctc', this.ctc);
    form.append('description', this.description); form.append('pdfFileName', this.uploadedFileName);
    await this.http.post('http://localhost:8080/api/internships/post', form).toPromise();
    this.companyName = this.title = this.location = this.ctc = this.description = '';
    this.pdfUploaded = false; this.fetchInternships();
  }

  async handleDelete(id: any) { await this.http.delete(`http://localhost:8080/api/internships/${id}`).toPromise(); this.fetchInternships(); }

  setScheduleValue(appId: any, field: string, value: any) {
    this.scheduleData = { ...this.scheduleData, [appId]: { ...(this.scheduleData[appId] || {}), [field]: value } };
  }
  getScheduleValue(appId: any, field: string) { return (this.scheduleData[appId]?.[field]) || ''; }

  async scheduleInterview(appId: any, status: any) {
    const data = this.scheduleData[appId];
    if (!data?.date || !data?.time || !data?.mode) return alert('Fill all fields');
    const params = new HttpParams()
      .set('applicationId', appId)
      .set('level', status === 'TEST_PASSED' ? 'L1' : status === 'L2_PENDING' ? 'L2' : 'HR')
      .set('date', data.date).set('time', data.time).set('mode', data.mode)
      .set('interviewerId', data.interviewerId || '');
    await this.http.post('http://localhost:8080/api/applications/schedule-interview', null, { params, responseType: 'text' }).toPromise();
    this.fetchAll();
  }

  async updateHrResult(id: any, result: string) {
    await this.http.post('http://localhost:8080/api/applications/hr-result', null, { 
      params: new HttpParams().set('applicationId', id).set('result', result), 
      responseType: 'text' 
    }).toPromise();
    this.fetchAll();
  }

  handleOfferFileChange(id: any, event: any) {
    const file = event.target.files?.[0];
    if (file) this.offerFiles = { ...this.offerFiles, [id]: file };
  }

  async uploadOfferLetter(id: any) {
    const file = this.offerFiles[id];
    if (!file) return alert('Select offer letter');
    const form = new FormData(); form.append('applicationId', id); form.append('file', file);
    await this.http.post('http://localhost:8080/api/applications/upload-offer-letter', form, { responseType: 'text' as 'json' }).toPromise();
    alert('Offer Uploaded'); this.fetchAll();
  }

  getOnboardingRecord(app: any) { return this.onboardingList.filter(ob => ob.applicationId === app.id).slice(-1)[0]; }
  employeeExists(email: string) { return !!this.employeeList.find(emp => emp.email === email); }
  showScheduleOptions(app: any) { return (app.status === 'TEST_PASSED' && app.interviewStatus !== 'L1_SCHEDULED') || (app.status === 'L2_PENDING' && app.interviewStatus !== 'L2_SCHEDULED') || (app.status === 'HR_PENDING' && app.interviewStatus !== 'HR_SCHEDULED') || app.l1InterviewerStatus === 'REJECTED' || app.l2InterviewerStatus === 'REJECTED'; }
  scheduleLabel(app: any) { return app.status === 'TEST_PASSED' ? 'Schedule L1' : app.status === 'L2_PENDING' ? 'Schedule L2' : 'Schedule HR'; }
  interviewerOptionsForApp(app: any) { return [{ id: 1, name: 'Kavya' }, { id: 2, name: 'Arun' }, { id: 3, name: 'Divya' }].filter(iv => iv.id !== app.l1InterviewerId); }
  statusColor(s: string) { return s === 'VERIFIED' ? '#10b981' : s === 'REJECTED' ? '#ef4444' : '#f59e0b'; }
}
